"""Core logic for STMap EXR → Adobe After Effects Mesh Warp .ffx presets.

Ported from ExportGenie-REF.py into a standalone, Maya-free module.
Pure Python + numpy (no OpenEXR / OpenImageIO required).
"""

from __future__ import annotations

import os
import struct
import zlib
from dataclasses import dataclass
from typing import Callable, Optional

import numpy as np


# AE Mesh Warp only supports these grid sizes (matches effect UI dropdown).
VALID_GRID_RES = (7, 11, 13, 19)
DEFAULT_GRID_RES = 11


# ---------------------------------------------------------------------------
# EXR reader (scanline float / half, uncompressed / ZIP / ZIPS)
# ---------------------------------------------------------------------------

def read_exr_float(path: str) -> np.ndarray:
    """Minimal OpenEXR reader for scanline float/half EXRs.

    Supports uncompressed, ZIP (16-line), and ZIPS (1-line) compression.
    Returns a numpy (H, W, 4) float32 array with R in channel 0 and G in
    channel 1 — the only channels an STMap needs.
    """
    with open(path, "rb") as f:
        data = f.read()

    if len(data) < 8 or data[:4] != b"\x76\x2f\x31\x01":
        raise ValueError(f"Not a valid EXR file: {path}")

    pos = 8  # skip magic + version

    channels = []  # [(name, pixel_type)]
    compression = 0
    data_window = (0, 0, 0, 0)

    while True:
        end = data.index(b"\x00", pos)
        attr_name = data[pos:end].decode("ascii")
        pos = end + 1
        if not attr_name:
            break

        end = data.index(b"\x00", pos)
        _attr_type = data[pos:end].decode("ascii")
        pos = end + 1

        attr_size = struct.unpack("<I", data[pos:pos + 4])[0]
        pos += 4
        attr_data = data[pos:pos + attr_size]
        pos += attr_size

        if attr_name == "channels":
            cp = 0
            while cp < len(attr_data) - 1:
                ne = attr_data.index(b"\x00", cp)
                ch_name = attr_data[cp:ne].decode("ascii")
                cp = ne + 1
                if not ch_name:
                    break
                ptype = struct.unpack("<I", attr_data[cp:cp + 4])[0]
                cp += 4
                cp += 12  # pLinear + reserved + xSampling + ySampling
                channels.append((ch_name, ptype))
        elif attr_name == "compression":
            compression = attr_data[0]
        elif attr_name == "dataWindow":
            data_window = struct.unpack("<iiii", attr_data)

    x1, y1, x2, y2 = data_window
    w = x2 - x1 + 1
    h = y2 - y1 + 1

    bpc = {0: 4, 1: 2, 2: 4}  # 0=uint32, 1=half, 2=float
    bytes_per_pixel = sum(bpc[ch[1]] for ch in channels)

    if compression == 0:
        lines_per_chunk = 1
    elif compression == 2:
        lines_per_chunk = 1
    elif compression == 3:
        lines_per_chunk = 16
    else:
        comp_names = {
            0: "none", 1: "rle", 2: "zips", 3: "zip", 4: "piz",
            5: "pxr24", 6: "b44", 7: "b44a", 8: "dwaa", 9: "dwab",
        }
        raise RuntimeError(
            "Unsupported EXR compression: {} ({}). "
            "STMap EXRs should use ZIP compression. "
            "Re-export with 'Zip (16 scanlines)'.".format(
                compression, comp_names.get(compression, "unknown")))

    num_chunks = (h + lines_per_chunk - 1) // lines_per_chunk

    offsets = []
    for _ in range(num_chunks):
        offsets.append(struct.unpack("<Q", data[pos:pos + 8])[0])
        pos += 8

    ch_index = {ch[0]: i for i, ch in enumerate(channels)}
    r_idx = ch_index.get("R", 0)
    g_idx = ch_index.get("G", 1 if len(channels) > 1 else 0)

    pixels = np.zeros((h, w, 4), dtype=np.float32)

    for chunk_i in range(num_chunks):
        off = offsets[chunk_i]
        y_start = struct.unpack("<i", data[off:off + 4])[0] - y1
        chunk_size = struct.unpack("<I", data[off + 4:off + 8])[0]
        raw = data[off + 8:off + 8 + chunk_size]

        n_lines = min(lines_per_chunk, h - y_start)
        expected = n_lines * w * bytes_per_pixel

        if compression in (2, 3) and len(raw) < expected:
            raw = zlib.decompress(raw)
            arr = np.frombuffer(raw, dtype=np.uint8).copy()
            arr[1:] -= np.uint8(128)
            arr = np.cumsum(arr, dtype=np.uint8)
            half = (len(arr) + 1) // 2
            tmp = np.empty_like(arr)
            tmp[0::2] = arr[:half]
            tmp[1::2] = arr[half:]
            raw = tmp.tobytes()

        line_bytes = w * bytes_per_pixel
        for ln in range(n_lines):
            y_row = y_start + ln
            if y_row >= h:
                break
            line_start = ln * line_bytes
            ch_offset = 0
            for ci, (_ch_name, ptype) in enumerate(channels):
                ch_bpc = bpc[ptype]
                ch_data = raw[line_start + ch_offset:
                              line_start + ch_offset + w * ch_bpc]
                ch_offset += w * ch_bpc

                if ci == r_idx:
                    out_ch = 0
                elif ci == g_idx:
                    out_ch = 1
                else:
                    continue

                if ptype == 2:
                    vals = np.frombuffer(ch_data, dtype="<f4")
                elif ptype == 1:
                    vals = np.frombuffer(ch_data, dtype="<f2").astype(np.float32)
                else:
                    vals = np.frombuffer(ch_data, dtype="<u4").astype(np.float32)
                pixels[y_row, :len(vals), out_ch] = vals

    return pixels


def read_stmap_pixels(stmap_path: str) -> tuple[int, int, np.ndarray]:
    """Read an EXR STMap and return (width, height, pixels)."""
    pixels = read_exr_float(stmap_path)
    h, w = pixels.shape[0], pixels.shape[1]
    return w, h, pixels


# ---------------------------------------------------------------------------
# Grid sampling
# ---------------------------------------------------------------------------

def sample_stmap(pixels: np.ndarray, img_w: int, img_h: int,
                 norm_x: float, norm_y: float) -> tuple[float, float]:
    """Bilinear sample of (R, G) at normalised coordinates. Clamped to [0,1]."""
    fx = max(0.0, min(norm_x * (img_w - 1), img_w - 1.001))
    fy = max(0.0, min(norm_y * (img_h - 1), img_h - 1.001))
    ix, iy = int(fx), int(fy)
    dx, dy = fx - ix, fy - iy
    ix1 = min(ix + 1, img_w - 1)
    iy1 = min(iy + 1, img_h - 1)

    p00 = pixels[iy, ix]
    p10 = pixels[iy, ix1]
    p01 = pixels[iy1, ix]
    p11 = pixels[iy1, ix1]
    w00 = (1 - dx) * (1 - dy)
    w10 = dx * (1 - dy)
    w01 = (1 - dx) * dy
    w11 = dx * dy
    u = float(p00[0] * w00 + p10[0] * w10 + p01[0] * w01 + p11[0] * w11)
    v = float(p00[1] * w00 + p10[1] * w10 + p01[1] * w01 + p11[1] * w11)
    return u, v


def build_stmap_grid(pixels: np.ndarray, img_w: int, img_h: int, grid_res: int,
                     overscan_x: float = 0.0, overscan_y: float = 0.0) -> list:
    """Sample an (grid_res+1) x (grid_res+1) grid from an STMap.

    Each entry: [src_x, src_y, dst_x, dst_y, sample_x, sample_y].
    Border points are linearly extrapolated from the interior to avoid
    collapsed edges from clipped STMap edge pixels.
    """
    grid = []
    for y in range(grid_res + 1):
        row = []
        for x in range(grid_res + 1):
            src_x = x / float(grid_res)
            src_y = y / float(grid_res)
            if overscan_x or overscan_y:
                sample_x = -overscan_x + src_x * (overscan_x * 2 + 1.0)
                sample_y = -overscan_y + src_y * (overscan_y * 2 + 1.0)
            else:
                sample_x = src_x
                sample_y = src_y
            dst_x, dst_y = sample_stmap(pixels, img_w, img_h, sample_x, sample_y)
            if overscan_x or overscan_y:
                dst_x = (dst_x + overscan_x) / (overscan_x * 2 + 1.0)
                dst_y = (dst_y + overscan_y) / (overscan_y * 2 + 1.0)
            row.append([src_x, src_y, dst_x, dst_y, sample_x, sample_y])
        grid.append(row)

    n = grid_res + 1
    for y in range(1, n - 1):
        for idx in (2, 3):
            grid[y][0][idx] = 2 * grid[y][1][idx] - grid[y][2][idx]
            grid[y][-1][idx] = 2 * grid[y][-2][idx] - grid[y][-3][idx]
    for x in range(n):
        for idx in (2, 3):
            grid[0][x][idx] = 2 * grid[1][x][idx] - grid[2][x][idx]
            grid[-1][x][idx] = 2 * grid[-2][x][idx] - grid[-3][x][idx]

    return grid


def detect_overscan(pixels: np.ndarray, img_w: int, img_h: int,
                    grid_res: int) -> tuple[float, float, float, float, float, float]:
    """Probe the STMap edges to infer UV range and overscan extent."""
    edge_samples = grid_res + 1
    min_u = float("inf")
    max_u = float("-inf")
    min_v = float("inf")
    max_v = float("-inf")
    for i in range(edge_samples):
        t = i / float(edge_samples - 1)
        for sx, sy in ((0.0, t), (1.0, t), (t, 0.0), (t, 1.0)):
            u, v = sample_stmap(pixels, img_w, img_h, sx, sy)
            min_u = min(min_u, u)
            max_u = max(max_u, u)
            min_v = min(min_v, v)
            max_v = max(max_v, v)
    overscan_x = max(0.0, -min(min_u, 0.0), max(max_u - 1.0, 0.0))
    overscan_y = max(0.0, -min(min_v, 0.0), max(max_v - 1.0, 0.0))
    return overscan_x, overscan_y, min_u, max_u, min_v, max_v


# ---------------------------------------------------------------------------
# .ffx binary preset writer (reverse-engineered AE preset format)
# ---------------------------------------------------------------------------

def _ae_fib(frames: int) -> tuple[int, int]:
    """Compute Fibonacci-based timing values required by the AE preset format."""
    v1, v2 = 0, 1
    while 4 * (v2 - 1) < int(frames):
        v1, v2 = v2, v1 + v2
    return v2 - 1, 4 * (v2 - 1)


